// Build the Claude API request body
const data = $input.first().json;
// Supadata returns { content: [{text, offset, duration}] } or { text: '...' }
const transcript = data.text
  || (Array.isArray(data.content) ? data.content.map(s => s.text).join(' ') : null)
  || data.transcript
  || null;
const chatId = $('Telegram Trigger').item.json.message.chat.id;

if (!transcript) {
  throw new Error('No se pudo obtener el transcript del video. Probá con otro link.');
}

const systemPrompt = `Sos un extractor de recetas. A partir de la transcripción de un video de cocina, extraé la receta en este formato JSON exacto:
{
  "name": "nombre de la receta",
  "type": "breakfast" o "lunch",
  "kcal": número (calorías estimadas),
  "protein": número (gramos de proteína),
  "carbs": número (gramos de hidratos),
  "fat": número (gramos de grasa),
  "tags": ["rápido", "sin TACC", "bajo HC" — solo los que apliquen],
  "ingredients": [{"name": "ingrediente", "amount": "cantidad"}],
  "steps": ["paso 1", "paso 2"]
}
Usa "breakfast" para desayunos y meriendas, "lunch" para almuerzos y cenas.
Estimá los macros si no están explícitos en el video.
Respondé ÚNICAMENTE con el JSON, sin texto adicional ni bloques de código markdown.`;

const requestBody = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  system: systemPrompt,
  messages: [
    {
      role: 'user',
      content: `Transcripción del video de TikTok:\n\n${transcript}`
    }
  ]
};

return [{ json: { requestBody, chatId } }];

const claudeResponse = $input.first().json;
const chatId = $('Armar request Claude').item.json.chatId;
const rawText = claudeResponse.content?.[0]?.text || '';

// Parse recipe JSON (handle markdown code blocks just in case)
let recipe;
try {
  recipe = JSON.parse(rawText.trim());
} catch {
  const match = rawText.match(/```(?:json)?\n?([\s\S]*?)\n?```/);
  if (match) {
    recipe = JSON.parse(match[1].trim());
  } else {
    throw new Error('Claude no devolvió un JSON válido: ' + rawText);
  }
}

// Format Telegram message (MarkdownV2 escaping)
const esc = (s) => String(s).replace(/[_*[\]()~`>#+\-=|{}.!]/g, '\\$&');

const typeLabel = recipe.type === 'breakfast' ? '🌅 Desayuno / Merienda' : '🍽️ Almuerzo / Cena';
const tagsText = recipe.tags?.length
  ? `\n🏷️ _${esc(recipe.tags.join(' · '))}_`
  : '';

const macros = `${esc(recipe.kcal)} kcal · ${esc(recipe.protein)}g prot · ${esc(recipe.carbs)}g HC · ${esc(recipe.fat)}g lip`;

const ingredients = recipe.ingredients
  .map(i => `  • *${esc(i.name)}*: ${esc(i.amount)}`)
  .join('\n');

const steps = recipe.steps
  .map((s, i) => `  ${i + 1}\\. ${esc(s)}`)
  .join('\n');

const message = [
  `🍳 *${esc(recipe.name)}*`,
  `${typeLabel}${tagsText}`,
  ``,
  `📊 *Macros estimados*`,
  `  ${macros}`,
  ``,
  `🛒 *Ingredientes*`,
  ingredients,
  ``,
  `👨‍🍳 *Preparación*`,
  steps,
  ``,
  `_Receta extraída por IA — revisá las cantidades\._`
].join('\n');

return [{ json: { recipe, message, chatId } }];
